package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.Dienstverband;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.enumtypes.Ritme;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.util.TemporalContext;
import com.google.common.collect.Multimap;
import com.google.common.collect.Ordering;
import com.google.common.collect.TreeMultimap;
import org.apache.commons.lang.builder.CompareToBuilder;
import org.jadira.usertype.dateandtime.joda.columnmapper.DateColumnLocalDateMapper;
import org.jadira.usertype.dateandtime.joda.columnmapper.TimestampColumnLocalDateTimeMapper;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.jdbc.core.SqlParameterValue;
import org.springframework.jdbc.support.rowset.SqlRowSet;
import org.springframework.transaction.annotation.Transactional;

import javax.sql.DataSource;
import java.io.Serializable;
import java.math.BigDecimal;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Timestamp;
import java.sql.Types;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

@Transactional
public class StandaardExtraSqlService implements ExtraSqlService {

    @Autowired
    private DataSource dataSource;

    private static final String FIND_OPDRACHTEN_GEBRUIKT_IN_REKENHOOFD =
            "select distinct rh.begindatum,pm.id as persoonid,om.opdrachtnr,os.datum_begin,os.datum_einde,rekenmodusctid from rekenhoofd rh"
                    + " join opdracht_master om on om.id=rh.opdrachtid" + " join persoon_master pm on pm.id=om.persoonid"
                    + " join opdracht_slice os on os.opdrachtid=om.id and recordfrom<=? and recordto>=?" + " where rh.begindatum<=? and rh.begindatum>=?";

    @Override
    @InitializeAdmin
    public Multimap<LocalDate, OpdrachtData> findOpdrachtenGebruiktInRekenResultaten(
            Admin admin, LocalDate beginDatum, LocalDate eindDatum,
            LocalDateTime rekenTijdstip) {
        LocalDateTime werkTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        TimestampColumnLocalDateTimeMapper localDateTimeMapper = new TimestampColumnLocalDateTimeMapper();
        Timestamp werkTijdstipSql = localDateTimeMapper.toNonNullValue(werkTijdstip);

        DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();

        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];

        args[0] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        args[1] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        args[2] = new SqlParameterValue(Types.DATE, localDateMapper.toNonNullValue(eindDatum));
        args[3] = new SqlParameterValue(Types.DATE, localDateMapper.toNonNullValue(beginDatum));
        List<OpdrachtData> resultaat = jdbc.query(FIND_OPDRACHTEN_GEBRUIKT_IN_REKENHOOFD, new OpdrachtDataRowMapper(), args);

        Multimap<LocalDate, OpdrachtData> datumToOpdrachtDatas = TreeMultimap.create(Ordering.natural(), OpdrachtDataComparator.DEFAULT);
        if (resultaat != null) {
            for (OpdrachtData item : resultaat) {
                datumToOpdrachtDatas.put(item.getBeginDatumRekenhoofd().dayOfMonth().withMinimumValue(), item);
            }
        }
        return datumToOpdrachtDatas;
    }

    public static class OpdrachtDataRowMapper implements RowMapper<OpdrachtData> {

        @Override
        public OpdrachtData mapRow(ResultSet rs, int rowNum) throws SQLException {
            DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();
            OpdrachtData opdrachtData = new OpdrachtData();
            opdrachtData.setBeginDatumRekenhoofd(localDateMapper.fromNonNullValue(rs.getDate("begindatum")));
            opdrachtData.setBeginDatum(localDateMapper.fromNonNullValue(rs.getDate("datum_begin")));
            opdrachtData.setEindDatum(localDateMapper.fromNonNullValue(rs.getDate("datum_einde")));
            opdrachtData.setPersoonId(rs.getInt("persoonid"));
            opdrachtData.setOpdrachtnr(rs.getInt("opdrachtnr"));
            opdrachtData.setRekenmodus(Rekenmodus.getById(rs.getInt("rekenmodusctid")));
            return opdrachtData;
        }
    }

    public static class OpdrachtDataComparator implements Comparator<OpdrachtData>, Serializable {

        public static final OpdrachtDataComparator DEFAULT = new OpdrachtDataComparator();

        @Override
        public int compare(OpdrachtData deel1, OpdrachtData deel2) {
            if (deel1 == deel2) {
                return 0;
            }
            return new CompareToBuilder().append(deel1.getBeginDatumRekenhoofd(), deel2.getBeginDatumRekenhoofd())
                    .append(deel1.getPersoonId(), deel2.getPersoonId()).append(deel1.getOpdrachtnr(), deel2.getOpdrachtnr())
                    .append(deel1.getBeginDatum(), deel2.getBeginDatum()).append(deel1.getEindDatum(), deel2.getEindDatum()).toComparison();
        }
    }

    private static final String FIND_OVERDRACHTEN_KWARTAAL_ANDERE_MAANDEN =
            "select distinct om.opdrachtnr, ro.begindatum,regimebvctid,bedragtypectid,sum(bedrag) as overdracht from rekenoverdracht ro"
                    + " join opdracht_master om on om.id=ro.opdrachtid"
                    + " where year(ro.begindatum)=? and ro.begindatum<? and floor((month(ro.begindatum)-1)/3+1)=? and om.persoonid=? group by 1,2,3,4 order by 1,2,3,4";

    @Override
    @InitializeAdmin
    public List<OverdrachtData> findOverdrachten(Admin admin, Integer persoonId, LocalDate beginDatum) {
        Integer kwartaal = TimeTools.bepaalKwartaal(beginDatum);

        DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();

        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];
        args[0] = new SqlParameterValue(Types.INTEGER, beginDatum.getYear());
        args[1] = new SqlParameterValue(Types.DATE, localDateMapper.toNonNullValue(beginDatum));
        args[2] = new SqlParameterValue(Types.INTEGER, kwartaal);
        args[3] = new SqlParameterValue(Types.INTEGER, persoonId);
        List<OverdrachtData> resultaat = jdbc.query(FIND_OVERDRACHTEN_KWARTAAL_ANDERE_MAANDEN, new OverdrachtDataRowMapper(), args);

        if (resultaat == null) {
            resultaat = new ArrayList<>();
        }
        return resultaat;
    }

    private static final String FIND_OVERDRACHTEN_PERIODE =
            "select distinct om.opdrachtnr, ro.begindatum,regimebvctid,bedragtypectid,sum(bedrag) as overdracht from rekenoverdracht ro"
                    + " join opdracht_master om on om.id=ro.opdrachtid"
                    + " where ro.begindatum>=? and ro.begindatum<=? and om.persoonid=? group by 1,2,3,4 order by 1,2,3,4";

    @Override
    @InitializeAdmin
    public List<OverdrachtData> findOverdrachtenPeriode(Admin admin, Integer persoonId, LocalDateInterval periode) {
        DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();

        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[3];
        args[0] = new SqlParameterValue(Types.DATE, localDateMapper.toNonNullValue(periode.getStart()));
        args[1] = new SqlParameterValue(Types.DATE, localDateMapper.toNonNullValue(periode.getEnd()));
        args[2] = new SqlParameterValue(Types.INTEGER, persoonId);
        List<OverdrachtData> resultaat = jdbc.query(FIND_OVERDRACHTEN_PERIODE, new OverdrachtDataRowMapper(), args);

        if (resultaat == null) {
            resultaat = new ArrayList<>();
        }
        return resultaat;
    }

    public static class OverdrachtDataRowMapper implements RowMapper<OverdrachtData> {

        @Override
        public OverdrachtData mapRow(ResultSet rs, int rowNum) throws SQLException {
            DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();
            OverdrachtData overdrachtData = new OverdrachtData();
            overdrachtData.setOpdrachtNr(rs.getInt("opdrachtnr"));
            overdrachtData.setBeginDatum(localDateMapper.fromNonNullValue(rs.getDate("begindatum")));
            int regimebvctid = rs.getInt("regimebvctid");
            overdrachtData.setRegimeBv(LnedefRegBv.getById(regimebvctid));
            int bedragtypectid = rs.getInt("bedragtypectid");
            overdrachtData.setRekenBedragType(RekenBedragType.getById(bedragtypectid));
            BigDecimal bedrag = rs.getBigDecimal("overdracht");
            overdrachtData.setBedrag(new Money(bedrag));
            return overdrachtData;
        }
    }

    private static final String BEPAAL_INDIENSTDATUM_OPDRACHT =
            "select min(actualfrom),max(actualto) from opper_slice ops left join rszppo rsz on ops.rszppoid = rsz.rszppoid"
                    + " where ops.opdrachtid = ?  and rsz.dienstverband = ?" + " and ops.recordfrom <= ? and ops.recordto > ?";

    @Override
    @InitializeAdmin
    public LocalDateInterval bepaalIndienstPeriode(Admin admin, Integer opdrachtid) {
        LocalDateTime werkTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        TimestampColumnLocalDateTimeMapper localDateTimeMapper = new TimestampColumnLocalDateTimeMapper();
        Timestamp werkTijdstipSql = localDateTimeMapper.toNonNullValue(werkTijdstip);

        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[4];

        args[0] = new SqlParameterValue(Types.INTEGER, opdrachtid);
        args[1] = new SqlParameterValue(Types.INTEGER, Dienstverband.JA.getCode());
        args[2] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        args[3] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        SqlRowSet rowSet = jdbc.queryForRowSet(BEPAAL_INDIENSTDATUM_OPDRACHT, args);
        return extractLocalDateInterval(rowSet);
    }

    private static final String QUERY_WEDDEBEPALING =
            "select wb.bron_beslissing, wb.synchronisatie,wb.gea_ritme,wb.gea_maanden,wb.gea_datum,wb.internnr,wb.versie  from weddebepaal_slice wb"
                    + " where wb.opdrachtid=? and wb.recordfrom <= ? and wb.recordto > ?" + " and wb.actualfrom <= ? and wb.actualto >= ?";

    @Override
    @InitializeAdmin
    public SimpelWeddebepaling getSimpelWeddebepaling(Admin admin, int opdrachtid, LocalDate datum) {
        LocalDateTime werkTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        TimestampColumnLocalDateTimeMapper localDateTimeMapper = new TimestampColumnLocalDateTimeMapper();
        DateColumnLocalDateMapper localDateMapper = new DateColumnLocalDateMapper();
        Timestamp werkTijdstipSql = localDateTimeMapper.toNonNullValue(werkTijdstip);
        java.sql.Date datumSql = localDateMapper.toNonNullValue(datum);

        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[5];

        args[0] = new SqlParameterValue(Types.INTEGER, opdrachtid);
        args[1] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        args[2] = new SqlParameterValue(Types.TIMESTAMP, werkTijdstipSql);
        args[3] = new SqlParameterValue(Types.DATE, datumSql);
        args[4] = new SqlParameterValue(Types.DATE, datumSql);
        SqlRowSet rowSet = jdbc.queryForRowSet(QUERY_WEDDEBEPALING, args);
        SimpelWeddebepaling weddebepaling = null;
        if (rowSet.first()) {
            weddebepaling = new SimpelWeddebepaling();
            weddebepaling.setBronBeslissing(rowSet.getInt(1));
            weddebepaling.setSynchronisatie(rowSet.getInt(2));
            weddebepaling.setGeldelijkeAncienniteitRitme(Ritme.getByCode(rowSet.getInt(3)));
            weddebepaling.setGeldelijkeAncienniteitMaanden(rowSet.getInt(4));
            java.sql.Date geaDate = rowSet.getDate(5);
            if (geaDate != null) {
                LocalDate geldelijkeAncienniteitDatum = LocalDate.fromDateFields(rowSet.getDate(5));
                weddebepaling.setGeldelijkeAncienniteitDatum(geldelijkeAncienniteitDatum);
            }
            weddebepaling.setInternNr(rowSet.getString(6));
            weddebepaling.setSchaalVersie((Integer) rowSet.getObject(7));
        }
        return weddebepaling;
    }

    private static final String BEPAAL_PERIODE_MAANDTOTALEN = "select min(begindatum),max(einddatum) from maandtotaal1";

    @Override
    @InitializeAdmin
    public LocalDateInterval bepaalPeriodeMaandtotalen(Admin admin) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);
        SqlRowSet rowSet = jdbc.queryForRowSet(BEPAAL_PERIODE_MAANDTOTALEN);
        return extractLocalDateInterval(rowSet);
    }

    private LocalDateInterval extractLocalDateInterval(SqlRowSet rowSet) {
        LocalDateInterval periode = null;
        if (rowSet.first()) {
            java.sql.Date beginDatumSql = rowSet.getDate(1);
            java.sql.Date eindDatumSql = rowSet.getDate(2);
            if (beginDatumSql != null && eindDatumSql != null) {
                LocalDate beginDatum = LocalDate.fromDateFields(rowSet.getDate(1));
                LocalDate eindDatum = LocalDate.fromDateFields(rowSet.getDate(2));
                periode = new LocalDateInterval(beginDatum, eindDatum);
            }
        }
        return periode;
    }

}
